create or replace function public.create_payroll_run(p_organization_id uuid,p_branch_id uuid,p_period_start date,p_period_end date,p_pay_date date,p_notes text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; v_no text; e public.employees%rowtype; s public.salary_structures%rowtype; v_overtime numeric; v_attendance numeric; v_leave numeric; v_overtime_pay numeric; v_gross numeric; v_employee_pension numeric; v_employer_pension numeric; v_tax numeric; v_deductions numeric; v_net numeric; t_gross numeric:=0; t_emp_pension numeric:=0; t_er_pension numeric:=0; t_tax numeric:=0; t_deductions numeric:=0; t_net numeric:=0; employee_count integer:=0; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant']::public.app_role[]) then raise exception 'Insufficient payroll permission'; end if; if p_period_end<p_period_start or p_pay_date<p_period_end then raise exception 'Invalid payroll period or pay date'; end if; if exists(select 1 from public.payroll_runs where organization_id=p_organization_id and status<>'cancelled' and daterange(period_start,period_end,'[]') && daterange(p_period_start,p_period_end,'[]')) then raise exception 'Payroll period overlaps an existing run'; end if; v_no:=public.next_document_number(p_organization_id,'PAY'); insert into public.payroll_runs(organization_id,branch_id,payroll_number,period_start,period_end,pay_date,status,notes,created_by) values(p_organization_id,p_branch_id,v_no,p_period_start,p_period_end,p_pay_date,'draft',nullif(trim(p_notes),''),p_actor_id) returning id into v_id; for e in select * from public.employees where organization_id=p_organization_id and status in ('active','on_leave') and hire_date<=p_period_end and (termination_date is null or termination_date>=p_period_start) order by employee_number loop select * into s from public.salary_structures where employee_id=e.id and organization_id=p_organization_id and is_active and effective_from<=p_period_end order by effective_from desc limit 1; if not found then continue; end if; select coalesce(sum(overtime_hours),0),coalesce(sum(case when status in ('present','late','remote') then 1 when status='half_day' then 0.5 else 0 end),0) into v_overtime,v_attendance from public.attendance_entries where organization_id=p_organization_id and employee_id=e.id and attendance_date between p_period_start and p_period_end; select coalesce(sum(days),0) into v_leave from public.leave_requests where organization_id=p_organization_id and employee_id=e.id and status='approved' and start_date<=p_period_end and end_date>=p_period_start; v_overtime_pay:=round(v_overtime*s.overtime_hourly_rate,2); v_gross:=round(s.base_salary+s.recurring_allowances+v_overtime_pay,2); v_employee_pension:=round(s.base_salary*s.employee_pension_rate/100,2); v_employer_pension:=round(s.base_salary*s.employer_pension_rate/100,2); v_tax:=round(greatest(v_gross-v_employee_pension,0)*s.income_tax_rate/100,2); v_deductions:=round(s.recurring_deductions,2); v_net:=round(greatest(v_gross-v_employee_pension-v_tax-v_deductions,0),2); insert into public.payroll_items(organization_id,payroll_run_id,employee_id,base_salary,allowances,overtime_pay,gross_pay,employee_pension,employer_pension,income_tax,other_deductions,net_pay,attendance_days,leave_days) values(p_organization_id,v_id,e.id,s.base_salary,s.recurring_allowances,v_overtime_pay,v_gross,v_employee_pension,v_employer_pension,v_tax,v_deductions,v_net,v_attendance,v_leave); t_gross:=t_gross+v_gross; t_emp_pension:=t_emp_pension+v_employee_pension; t_er_pension:=t_er_pension+v_employer_pension; t_tax:=t_tax+v_tax; t_deductions:=t_deductions+v_deductions; t_net:=t_net+v_net; employee_count:=employee_count+1; end loop; if employee_count=0 then raise exception 'No active employees with salary structures were found'; end if; update public.payroll_runs set gross_pay=t_gross,employee_pension=t_emp_pension,employer_pension=t_er_pension,income_tax=t_tax,other_deductions=t_deductions,net_pay=t_net where id=v_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'payroll.run.created','payroll_run',v_id,jsonb_build_object('number',v_no,'employees',employee_count,'net_pay',t_net)); return jsonb_build_object('id',v_id,'number',v_no,'amount',t_net,'employees',employee_count); end $$;

create or replace function public.approve_payroll_run(p_organization_id uuid,p_payroll_run_id uuid,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare r public.payroll_runs%rowtype; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin']::public.app_role[]) then raise exception 'Insufficient payroll approval permission'; end if; select * into r from public.payroll_runs where id=p_payroll_run_id and organization_id=p_organization_id for update; if not found or r.status<>'draft' then raise exception 'Draft payroll run not found'; end if; update public.payroll_runs set status='approved',approved_by=p_actor_id,updated_at=now() where id=r.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'payroll.run.approved','payroll_run',r.id,jsonb_build_object('number',r.payroll_number,'net_pay',r.net_pay)); return jsonb_build_object('id',r.id,'number',r.payroll_number,'amount',r.net_pay); end $$;

revoke all on function public.create_payroll_run(uuid,uuid,date,date,date,text,uuid) from public; grant execute on function public.create_payroll_run(uuid,uuid,date,date,date,text,uuid) to authenticated;
revoke all on function public.approve_payroll_run(uuid,uuid,uuid) from public; grant execute on function public.approve_payroll_run(uuid,uuid,uuid) to authenticated;